(window.webpackJsonp=window.webpackJsonp||[]).push([[953],{898:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">boxTypes</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">truckSize</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maximumUnits = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">boxTypes, truckSize</span>) </span>{\\n    boxTypes.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>b[<span class=\\"hljs-number\\">1</span>]-a[<span class=\\"hljs-number\\">1</span>])\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> select=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;boxTypes.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> [count,size]=boxTypes[i]\\n        <span class=\\"hljs-keyword\\">if</span>(count+select&gt;=truckSize){\\n            res+=(truckSize-select)*size\\n            <span class=\\"hljs-keyword\\">return</span> res\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            res+=count*size\\n            select+=count\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-units-on-a-truck","hasThinking":false,"content":"<p>\u8bf7\u4f60\u5c06\u4e00\u4e9b\u7bb1\u5b50\u88c5\u5728 <strong>\u4e00\u8f86\u5361\u8f66</strong> \u4e0a\u3002\u7ed9\u4f60\u4e00\u4e2a\u4e8c\u7ef4\u6570\u7ec4 <code>boxTypes</code> \uff0c\u5176\u4e2d <code>boxTypes[i] = [numberOfBoxes<sub>i</sub>, numberOfUnitsPerBox<sub>i</sub>]</code> \uff1a</p>\\n\\n<ul>\\n\\t<li><code>numberOfBoxes<sub>i</sub></code> \u662f\u7c7b\u578b <code>i</code> \u7684\u7bb1\u5b50\u7684\u6570\u91cf\u3002</li>\\n\\t<li><code>numberOfUnitsPerBox<sub>i</sub></code><sub> </sub>\u662f\u7c7b\u578b <code>i</code>\xa0\u6bcf\u4e2a\u7bb1\u5b50\u53ef\u4ee5\u88c5\u8f7d\u7684\u5355\u5143\u6570\u91cf\u3002</li>\\n</ul>\\n\\n<p>\u6574\u6570 <code>truckSize</code> \u8868\u793a\u5361\u8f66\u4e0a\u53ef\u4ee5\u88c5\u8f7d <strong>\u7bb1\u5b50</strong> \u7684 <strong>\u6700\u5927\u6570\u91cf</strong> \u3002\u53ea\u8981\u7bb1\u5b50\u6570\u91cf\u4e0d\u8d85\u8fc7 <code>truckSize</code> \uff0c\u4f60\u5c31\u53ef\u4ee5\u9009\u62e9\u4efb\u610f\u7bb1\u5b50\u88c5\u5230\u5361\u8f66\u4e0a\u3002</p>\\n\\n<p>\u8fd4\u56de\u5361\u8f66\u53ef\u4ee5\u88c5\u8f7d\xa0<strong>\u5355\u5143</strong> \u7684 <strong>\u6700\u5927</strong> \u603b\u6570<em>\u3002</em></p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>boxTypes = [[1,3],[2,2],[3,1]], truckSize = 4\\n<strong>\u8f93\u51fa\uff1a</strong>8\\n<strong>\u89e3\u91ca\uff1a</strong>\u7bb1\u5b50\u7684\u60c5\u51b5\u5982\u4e0b\uff1a\\n- 1 \u4e2a\u7b2c\u4e00\u7c7b\u7684\u7bb1\u5b50\uff0c\u91cc\u9762\u542b 3 \u4e2a\u5355\u5143\u3002\\n- 2 \u4e2a\u7b2c\u4e8c\u7c7b\u7684\u7bb1\u5b50\uff0c\u6bcf\u4e2a\u91cc\u9762\u542b 2 \u4e2a\u5355\u5143\u3002\\n- 3 \u4e2a\u7b2c\u4e09\u7c7b\u7684\u7bb1\u5b50\uff0c\u6bcf\u4e2a\u91cc\u9762\u542b 1 \u4e2a\u5355\u5143\u3002\\n\u53ef\u4ee5\u9009\u62e9\u7b2c\u4e00\u7c7b\u548c\u7b2c\u4e8c\u7c7b\u7684\u6240\u6709\u7bb1\u5b50\uff0c\u4ee5\u53ca\u7b2c\u4e09\u7c7b\u7684\u4e00\u4e2a\u7bb1\u5b50\u3002\\n\u5355\u5143\u603b\u6570 = (1 * 3) + (2 * 2) + (1 * 1) = 8</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>boxTypes = [[5,10],[2,5],[4,7],[3,9]], truckSize = 10\\n<strong>\u8f93\u51fa\uff1a</strong>91\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= boxTypes.length <= 1000</code></li>\\n\\t<li><code>1 <= numberOfBoxes<sub>i</sub>, numberOfUnitsPerBox<sub>i</sub> <= 1000</code></li>\\n\\t<li><code>1 <= truckSize <= 10<sup>6</sup></code></li>\\n</ul>\\n","title":"1710. \u5361\u8f66\u4e0a\u7684\u6700\u5927\u5355\u5143\u6570","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u6392\u5e8f"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1710"}')}}]);